def count_frequencies(data):
    frequency = {}
    for entry in data:
        for key, value in entry.items():
            if key not in frequency:
                frequency[key] = {}
            if value not in frequency[key]:
                frequency[key][value] = 0
            frequency[key][value] += 1
    return frequency

